// 3D Perlin noise + gradient color mix adapted from ShaderGradient.
// SPDX-License-Identifier: MIT
// Copyright (c) 2022 ruucm, stone-skipper — https://github.com/ruucm/shadergradient
//
// The `cnoise(vec3)` 3D classic Perlin noise function (and its
// mod289 / permute / taylorInvSqrt / fade helpers) is copied VERBATIM from
// ShaderGradient, which sourced it from https://github.com/hughsk/glsl-noise
// (periodic/3d.glsl, (c) Stefan Gustavson).
//
// The N-stop linear color blend evaluates an arbitrary number of color stops
// (2..6) using dynamic uniform-array indexing (GLSL ES 3.00), replacing the
// original 3-stop two-stage mix. The smooth "Halo" look is preserved.
// See THIRD_PARTY_NOTICES.md for full attribution.

/** Vertex shader (WebGL2 / GLSL ES 3.00) — a single fullscreen triangle. */
export const VERTEX_SHADER = /* glsl */ `#version 300 es
precision highp float;

// Fullscreen triangle — no attributes, no VAO, no MVP. Driven by gl_VertexID.
// Draw with: gl.drawArrays(gl.TRIANGLES, 0, 3)
out vec2 vUv;

void main() {
  vec2 verts[3] = vec2[3](vec2(-1.0, -1.0), vec2(3.0, -1.0), vec2(-1.0, 3.0));
  vec2 p = verts[gl_VertexID];
  vUv = p * 0.5 + 0.5;          // 0..1, with overscan beyond 1 on the big triangle
  gl_Position = vec4(p, 0.0, 1.0);
}
`;

/** Fragment shader (WebGL2 / GLSL ES 3.00). */
export const FRAGMENT_SHADER = /* glsl */ `#version 300 es
precision highp float;

in vec2 vUv;

uniform vec3  uColors[6];
uniform int   uColorCount;
uniform float uTime;     // seconds
uniform float uSpeed;    // animation rate (Halo: 0.4)
uniform float uDensity;  // noise frequency (Halo: 1.3)
uniform float uStrength; // color3 "halo" contribution; remapped, NOT raw mix (Halo src: 4)
uniform float uAngle;    // diagonal axis in degrees (Halo rotationZ: 50)
uniform float uAspect;   // canvas.width / canvas.height — MUST be set each resize/frame
uniform float uGrain;    // film grain amount, ~0..0.3 (0 = off)
uniform float uOpacity;  // 0..1

out vec4 fragColor;

// ---- 3D classic Perlin noise (cnoise) — verbatim glsl-noise / ShaderGradient, MIT ----
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec4 permute(vec4 x) { return mod289(((x*34.0)+1.0)*x); }
vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }
vec3 fade(vec3 t) { return t*t*t*(t*(t*6.0-15.0)+10.0); }

float cnoise(vec3 P) {
  vec3 Pi0 = floor(P);
  vec3 Pi1 = Pi0 + vec3(1.0);
  Pi0 = mod289(Pi0);
  Pi1 = mod289(Pi1);
  vec3 Pf0 = fract(P);
  vec3 Pf1 = Pf0 - vec3(1.0);
  vec4 ix = vec4(Pi0.x, Pi1.x, Pi0.x, Pi1.x);
  vec4 iy = vec4(Pi0.yy, Pi1.yy);
  vec4 iz0 = Pi0.zzzz;
  vec4 iz1 = Pi1.zzzz;

  vec4 ixy = permute(permute(ix) + iy);
  vec4 ixy0 = permute(ixy + iz0);
  vec4 ixy1 = permute(ixy + iz1);

  vec4 gx0 = ixy0 * (1.0 / 7.0);
  vec4 gy0 = fract(floor(gx0) * (1.0 / 7.0)) - 0.5;
  gx0 = fract(gx0);
  vec4 gz0 = vec4(0.5) - abs(gx0) - abs(gy0);
  vec4 sz0 = step(gz0, vec4(0.0));
  gx0 -= sz0 * (step(0.0, gx0) - 0.5);
  gy0 -= sz0 * (step(0.0, gy0) - 0.5);

  vec4 gx1 = ixy1 * (1.0 / 7.0);
  vec4 gy1 = fract(floor(gx1) * (1.0 / 7.0)) - 0.5;
  gx1 = fract(gx1);
  vec4 gz1 = vec4(0.5) - abs(gx1) - abs(gy1);
  vec4 sz1 = step(gz1, vec4(0.0));
  gx1 -= sz1 * (step(0.0, gx1) - 0.5);
  gy1 -= sz1 * (step(0.0, gy1) - 0.5);

  vec3 g000 = vec3(gx0.x,gy0.x,gz0.x);
  vec3 g100 = vec3(gx0.y,gy0.y,gz0.y);
  vec3 g010 = vec3(gx0.z,gy0.z,gz0.z);
  vec3 g110 = vec3(gx0.w,gy0.w,gz0.w);
  vec3 g001 = vec3(gx1.x,gy1.x,gz1.x);
  vec3 g101 = vec3(gx1.y,gy1.y,gz1.y);
  vec3 g011 = vec3(gx1.z,gy1.z,gz1.z);
  vec3 g111 = vec3(gx1.w,gy1.w,gz1.w);

  vec4 norm0 = taylorInvSqrt(vec4(dot(g000,g000), dot(g010,g010), dot(g100,g100), dot(g110,g110)));
  g000 *= norm0.x; g010 *= norm0.y; g100 *= norm0.z; g110 *= norm0.w;
  vec4 norm1 = taylorInvSqrt(vec4(dot(g001,g001), dot(g011,g011), dot(g101,g101), dot(g111,g111)));
  g001 *= norm1.x; g011 *= norm1.y; g101 *= norm1.z; g111 *= norm1.w;

  float n000 = dot(g000, Pf0);
  float n100 = dot(g100, vec3(Pf1.x, Pf0.yz));
  float n010 = dot(g010, vec3(Pf0.x, Pf1.y, Pf0.z));
  float n110 = dot(g110, vec3(Pf1.xy, Pf0.z));
  float n001 = dot(g001, vec3(Pf0.xy, Pf1.z));
  float n101 = dot(g101, vec3(Pf1.x, Pf0.y, Pf1.z));
  float n011 = dot(g011, vec3(Pf0.x, Pf1.yz));
  float n111 = dot(g111, Pf1);

  vec3 fade_xyz = fade(Pf0);
  vec4 n_z = mix(vec4(n000, n100, n010, n110), vec4(n001, n101, n011, n111), fade_xyz.z);
  vec2 n_yz = mix(n_z.xy, n_z.zw, fade_xyz.y);
  float n_xyz = mix(n_yz.x, n_yz.y, fade_xyz.x);
  return 2.2 * n_xyz;          // ~[-2.2, 2.2]
}

// Sine-free per-pixel + per-frame hash (Dave Hoskins, MIT).
// Avoids the diagonal aliasing / scan-line artefact of sin-based hashes.
float hash13(vec3 p3) {
  p3 = fract(p3 * 0.1031);
  p3 += dot(p3, p3.zyx + 31.32);
  return fract((p3.x + p3.y) * p3.z);
}

void main() {
  vec2 p = vUv - 0.5;
  p.x *= uAspect;
  float t = uTime * uSpeed;
  float a = radians(uAngle);
  vec2 dir = vec2(cos(a), sin(a));

  // Two-octave warp: coarse low-frequency base + finer faster layer for living movement.
  float warp = cnoise(vec3(p * uDensity, t)) * uStrength * 0.15
             + cnoise(vec3(p * uDensity * 2.3 + 4.0, t * 1.3)) * uStrength * 0.07;

  // One smooth diagonal coordinate spanning the whole frame, 0..1. The 0.95 slope
  // makes the 3 colors sweep edge-to-edge; no hard transition anywhere.
  float m = clamp(dot(p, dir) * 0.95 + 0.5 + warp, 0.0, 1.0);

  // N-stop linear blend (2..6 stops, like a CSS linear-gradient).
  // Dynamic array indexing is valid in GLSL ES 3.00 with uniform-array indices.
  int n = max(uColorCount, 2);
  float seg = m * float(n - 1);
  int i = clamp(int(floor(seg)), 0, n - 2);
  float f = seg - float(i);
  vec3 col = mix(uColors[i], uColors[i + 1], f);

  if (uGrain > 0.0) {
    float g = hash13(vec3(gl_FragCoord.xy, floor(uTime * 60.0)));
    col += (g - 0.5) * uGrain;
  }
  fragColor = vec4(clamp(col, 0.0, 1.0), uOpacity);
}
`;
